import { readdir,stat } from "node:fs/promises";import { join } from "node:path";
const dir=join(process.cwd(),".output/public/assets");const assets=[];for(const name of await readdir(dir)){const info=await stat(join(dir,name));if(info.isFile())assets.push({name,bytes:info.size})}assets.sort((a,b)=>b.bytes-a.bytes);const js=assets.filter((item)=>item.name.endsWith(".js"));const css=assets.filter((item)=>item.name.endsWith(".css"));const maxJs=js[0]?.bytes??0;const maxCss=css[0]?.bytes??0;console.log(JSON.stringify({assets:assets.length,totalBytes:assets.reduce((sum,item)=>sum+item.bytes,0),largestJs:js[0]??null,largestCss:css[0]??null},null,2));if(maxJs>260*1024)throw new Error("Chunk JavaScript acima de 260 KiB.");if(maxCss>130*1024)throw new Error("CSS acima de 130 KiB.");
